scripts.build:cloudflare:
npm run build:pages && node --input-type=module -e "import fs from 'node:fs';
import path from 'node:path';
const oldUrl = 'https://crimson-tavern.boarder-72pound.chatgpt.site/api/vault';
function rewrite(dir) {
  for (const name of fs.readdirSync(dir)) {
    const file = path.join(dir, name);
    const stat = fs.statSync(file);
    if (stat.isDirectory()) rewrite(file);
    else {
      const source = fs.readFileSync(file, 'utf8');
      if (source.includes(oldUrl)) fs.writeFileSync(file, source.split(oldUrl).join('/api/vault'));
    }
  }
}
rewrite('dist-pages');
fs.writeFileSync('worker-entry.js', "import { setD1 } from \"./db/index.ts\";\nimport { GET, OPTIONS, PATCH, POST, PUT } from \"./app/api/vault/route.ts\";\n\nexport default {\n  async fetch(request, env) {\n    const url = new URL(request.url);\n    if (url.pathname === \"/api/vault\" || url.pathname === \"/api/vault/\") {\n      setD1(env.DB);\n      switch (request.method.toUpperCase()) {\n        case \"OPTIONS\": return OPTIONS();\n        case \"GET\": return GET(request);\n        case \"PUT\": return PUT(request);\n        case \"POST\": return POST(request);\n        case \"PATCH\": return PATCH(request);\n        default:\n          return Response.json(\n            { error: \"不支持这种请求方式。\" },\n            { status: 405, headers: { Allow: \"GET, POST, PUT, PATCH, OPTIONS\", \"Cache-Control\": \"no-store\" } },\n          );\n      }\n    }\n    return env.ASSETS.fetch(request);\n  },\n};\n");
"
